42	use			PoC.simulation.all;
43	use			PoC.waveform.all;
44	
45	
46	entity fifo_cc_got_tb is
47	end entity;
48	
49	
50	architecture tb of fifo_cc_got_tb is
51		constant CLOCK_FREQ			: FREQ					:= 100 MHz;
52	
53	  -- component generics
54	  constant D_BITS         : positive := 8;
55	  constant MIN_DEPTH      : positive := 30;
56	  constant ESTATE_WR_BITS : natural  := 2;
57	  constant FSTATE_RD_BITS : natural  := 2;
58	
59	  -- Clock Control
60	  signal rst  : std_logic;
61	  signal clk  : std_logic;
62	
63	begin
64		-- initialize global simulation status
65		simInitialize;
66		-- generate global testbench clock
67		simGenerateClock(clk,		CLOCK_FREQ);
68		simGenerateWaveform(rst,	simGenerateWaveform_Reset(Pause => 10 ns, ResetPulse => 10 ns));
69	
70	  genDUTs: for c in 0 to 7 generate
71			constant DATA_REG   : boolean :=  c mod 2 > 0;
72			constant STATE_REG  : boolean :=  c mod 4 > 1;
73			constant OUTPUT_REG : boolean :=  c mod 8 > 3;
74	
75			constant simTestID	: T_SIM_TEST_ID			:= simCreateTest("Test setup for DATA_REG=" & boolean'image(DATA_REG) & " STATE_REG=" & BOOLEAN'image(STATE_REG) & " OUTPUT_REG=" & boolean'image(OUTPUT_REG));
76	
77	    -- Local Component Ports
78	    signal put				: std_logic;
79	    signal din				: std_logic_vector(D_BITS-1 downto 0);
80	    signal full				: std_logic;
81			signal estate_wr	: std_logic_vector(ESTATE_WR_BITS - 1 downto 0);
82	    signal got				: std_logic;
83	    signal dout				: std_logic_vector(D_BITS-1 downto 0);
84	    signal valid			: std_logic;
85			signal fstate_rd	: std_logic_vector(FSTATE_RD_BITS - 1 downto 0);
86	
87	  begin
88	
89	    DUT : entity PoC.fifo_cc_got
90	      generic map (
91	        D_BITS         => D_BITS,
92	        MIN_DEPTH      => MIN_DEPTH,
93	        STATE_REG      => STATE_REG,
94	        DATA_REG       => DATA_REG,
95	        OUTPUT_REG     => OUTPUT_REG,
96	        ESTATE_WR_BITS => ESTATE_WR_BITS,
97	        FSTATE_RD_BITS => FSTATE_RD_BITS
98	      )
99	      port map (
100	        rst       => rst,
101	        clk       => clk,
102	        put       => put,
103	        din       => din,
104	        full      => full,
105	        estate_wr => estate_wr,
106	        got       => got,
107	        dout      => dout,
108	        valid     => valid,
109	        fstate_rd => fstate_rd
110	      );
111	
112	    -- Writer
113	    procWriter : process
114				constant simProcessID	: T_SIM_PROCESS_ID := simRegisterProcess(simTestID, "Writer for DATA_REG=" & boolean'image(DATA_REG) & " STATE_REG=" & BOOLEAN'image(STATE_REG) & " OUTPUT_REG=" & boolean'image(OUTPUT_REG));
115	    begin
116	      din <= (others => '-');
117	      put <= '0';
118	      wait until rising_edge(clk) and rst = '0';
119	
120	      for i in 0 to 2**(D_BITS-1)-1 loop
121	        din <= std_logic_vector(to_unsigned(i, D_BITS));
122	        put <= '1';
123	        wait until rising_edge(clk) and full = '0';
124	      end loop;
125	
126	      for i in 2**(D_BITS-1) to 2**D_BITS-1 loop
127	        din <= (others => '-');
128	        put <= '0';
129	        wait until rising_edge(clk) and valid = '0';
130	        din <= std_logic_vector(to_unsigned(i, D_BITS));
131	        put <= '1';
132	        wait until rising_edge(clk);
133	      end loop;
134	
135	      din <= (others => '-');
136	      put <= '0';
137	
138	      -- This process is finished
139				simDeactivateProcess(simProcessID);
140				wait;  -- forever
141	    end process;
142	
143	    -- Reader
144			procReader : process
145				constant simProcessID	: T_SIM_PROCESS_ID := simRegisterProcess(simTestID, "Reader for DATA_REG=" & boolean'image(DATA_REG) & " STATE_REG=" & BOOLEAN'image(STATE_REG) & " OUTPUT_REG=" & boolean'image(OUTPUT_REG));
146	    begin
147	      got <= '0';
148	      for i in 0 to 2**D_BITS-1 loop
149	        wait until rising_edge(clk) and valid = '1';
150					simAssertion((dout = std_logic_vector(to_unsigned(i, D_BITS))), "Output failure in configuration " & integer'image(c) & " @ Pos " & INTEGER'image(i));
151	        got <= '1';
152	        wait until rising_edge(clk);
153	        got <= '0';
154	        wait until rising_edge(clk);
155	      end loop;
156	
157	      -- This process is finished
158				simDeactivateProcess(simProcessID);
159				simFinalizeTest(simTestID);
160				wait;  -- forever
161	    end process;
162	  end generate genDUTs;
163	end architecture;
