288		procedure simGenerateClock(
289			signal	 Clock			: out	std_logic;
290			constant Frequency	: in	FREQ;
291			constant Phase			: in	T_PHASE			:=	0 deg;
292			constant DutyCycle	: in	T_DUTYCYCLE	:= 50 percent;
293			constant Wander			: in	T_WANDER		:=	0 permil
294		) is
295			constant Period : time := to_time(Frequency);
296		begin
297			simGenerateClock(C_SIM_DEFAULT_TEST_ID, Clock, Period, Phase, DutyCycle, Wander);
298		end procedure;
299	
300		procedure simGenerateClock(
301			constant TestID			: in	T_SIM_TEST_ID;
302			signal	 Clock			: out	std_logic;
303			constant Frequency	: in	FREQ;
304			constant Phase			: in	T_PHASE			:=	0 deg;
305			constant DutyCycle	: in	T_DUTYCYCLE	:= 50 percent;
306			constant Wander			: in	T_WANDER		:=	0 permil
307		) is
308			constant Period : time := to_time(Frequency);
309		begin
310			simGenerateClock(TestID, Clock, Period, Phase, DutyCycle, Wander);
311		end procedure;
312	
313		procedure simGenerateClock(
314			signal	 Clock			: out	std_logic;
315			constant Period			: in	time;
316			constant Phase			: in	T_PHASE			:=	0 deg;
317			constant DutyCycle	: in	T_DUTYCYCLE	:= 50 percent;
318			constant Wander			: in	T_WANDER		:=	0 permil
319		) is
320		begin
321			simGenerateClock(C_SIM_DEFAULT_TEST_ID, Clock, Period, Phase, DutyCycle, Wander);
322		end procedure;
323	
324		procedure simGenerateClock(
325			constant TestID			: in	T_SIM_TEST_ID;
326			signal	 Clock			: out	std_logic;
327			constant Period			: in	time;
328			constant Phase			: in	T_PHASE			:=	0 deg;
329			constant DutyCycle	: in	T_DUTYCYCLE	:= 50 percent;
330			constant Wander			: in	T_WANDER		:=	0 permil
331		) is
332			constant NormalizedPhase		: T_PHASE		:= ite((Phase >= 0 deg), Phase, Phase + 360 deg);						-- move Phase into the range of 0° to 360°
333			constant PhaseAsFactor			: REAL			:= real(NormalizedPhase / 1 second) / 1296000.0;						-- 1,296,000 = 3,600 seconds * 360 degree per cycle
334			constant WanderAsFactor			: REAL			:= real(Wander / 1 ppb) / 1.0e9;
335			constant DutyCycleAsFactor	: REAL			:= real(DutyCycle / 1 permil) / 1000.0;
336			constant Delay							: time			:= Period * PhaseAsFactor;
337			constant TimeHigh						: time			:= Period * DutyCycleAsFactor + (Period * (WanderAsFactor / 2.0));	-- add 50% wander to the high level
338			constant TimeLow						: time			:= Period - TimeHigh + (Period * WanderAsFactor);						-- and 50% to the low level
339			constant ClockAfterRun_cy		: positive	:= 5;
340	
341			constant PROCESS_ID					: T_SIM_PROCESS_ID	:= simRegisterProcess(TestID, "simGenerateClock(period=" & to_string(Period, 2) & ")", IsLowPriority => TRUE);
342		begin
343			-- report "simGenerateClock: (Instance: '" & Clock'instance_name & "')" & LF &
344				-- "Period: "						& TIME'image(Period) & LF &
345				-- "Phase: "							& T_PHASE'image(Phase) & LF &
346				-- "DutyCycle: "					& T_DUTYCYCLE'image(DutyCycle) & LF &
347				-- "PhaseAsFactor: "			& REAL'image(PhaseAsFactor) & LF &
348				-- "WanderAsFactor: "		& REAL'image(WanderAsFactor) & LF &
349				-- "DutyCycleAsFactor: "	& REAL'image(DutyCycleAsFactor) & LF &
350				-- "Delay: "							& TIME'image(Delay) & LF &
351				-- "TimeHigh: "					& TIME'image(TimeHigh) & LF &
352				-- "TimeLow: "						& TIME'image(TimeLow)
353				-- severity NOTE;
354	
355			if (Delay = 0 ns) then
356				null;
357			elsif (Delay <= TimeLow) then
358				Clock		<= '0';
359				wait for Delay;
360			else
361				Clock		<= '1';
362				wait for Delay - TimeLow;
363				Clock		<= '0';
364				wait for TimeLow;
365			end if;
366			Clock		<= '1';
367			while not simIsStopped(TestID) loop
368				wait for TimeHigh;
369				Clock		<= '0';
370				wait for TimeLow;
371				Clock		<= '1';
372			end loop;
373			simDeactivateProcess(PROCESS_ID);
374			-- create N more cycles to allow other processes to recognize the stop condition (clock after run)
375			for i in 1 to ClockAfterRun_cy loop
376				wait for TimeHigh;
377				Clock		<= '0';
378				wait for TimeLow;
379				Clock		<= '1';
380			end loop;
381			Clock		<= '0';
382		end procedure;
383	
384		type T_SIM_NORMAL_DIST_PARAMETER is record
385			StandardDeviation		: REAL;
386			Mean								: REAL;
387		end record;
388		type T_JITTER_DISTRIBUTION is array (natural range <>) of T_SIM_NORMAL_DIST_PARAMETER;
389	
390		procedure simGenerateClock2(
391			constant	TestID	: in	T_SIM_TEST_ID;
392			signal		Clock		: out	std_logic;
393			signal		Debug		: out	REAL;
394			constant	Period	: in	time
395		) is
396			constant TimeHigh							: time			:= Period * 0.5;
397			constant TimeLow							: time			:= Period - TimeHigh;
398			constant JitterPeakPeak				: REAL			:= 0.1;		-- UI
399			constant JitterAsFactor				: REAL			:= JitterPeakPeak / 4.0;	-- Maximum jitter per edge
400			constant JitterDistribution		: T_JITTER_DISTRIBUTION	:= (
401				-- 0 => (StandardDeviation => 0.2, Mean => -0.4),
402				-- 1 => (StandardDeviation => 0.2, Mean =>  0.4)
403	
404				-- 0 => (StandardDeviation => 0.2, Mean => -0.4),
405				-- 1 => (StandardDeviation => 0.3, Mean => -0.1),
406				-- 2 => (StandardDeviation => 0.5, Mean =>  0.0),
407				-- 3 => (StandardDeviation => 0.3, Mean =>  0.1),
408				-- 4 => (StandardDeviation => 0.2, Mean =>  0.4)
409	
410				0 => (StandardDeviation => 0.15,	Mean => -0.6),
411				1 => (StandardDeviation => 0.2,		Mean => -0.3),
412				2 => (StandardDeviation => 0.25,	Mean => -0.2),
413				3 => (StandardDeviation => 0.3,		Mean =>  0.0),
414				4 => (StandardDeviation => 0.25,	Mean =>  0.2),
415				5 => (StandardDeviation => 0.2,		Mean =>  0.3),
416				6 => (StandardDeviation => 0.15,	Mean =>  0.6)
417			);
418			variable Seed									: T_SIM_RAND_SEED;
419			variable rand									: REAL;
420			variable Jitter								: REAL;
421			variable Index								: natural;
422	
423			constant ClockAfterRun_cy			: positive	:= 5;
424		begin
425			Clock		<= '1';
426			randInitializeSeed(Seed);
427	
428			while not simIsStopped(TestID) loop
429				ieee.math_real.Uniform(Seed.Seed1, Seed.Seed2, rand);
430				Index		:= scale(rand, 0, JitterDistribution'length * 10) mod JitterDistribution'length;
431				randNormalDistributedValue(Seed, rand, JitterDistribution(Index).StandardDeviation, JitterDistribution(Index).Mean, -1.0, 1.0);
432	
433				Jitter := JitterAsFactor * rand;
434				Debug		<= rand;
435	
436				-- Debug		<= integer(rand * 256.0 + 256.0);
437				wait for TimeHigh + (Period * Jitter);
438				Clock		<= '0';
439				wait for TimeLow + (Period * Jitter);
440				Clock		<= '1';
441			end loop;
442			-- create N more cycles to allow other processes to recognize the stop condition (clock after run)
443			for i in 1 to ClockAfterRun_cy loop
444				wait for TimeHigh;
445				Clock		<= '0';
446				wait for TimeLow;
447				Clock		<= '1';
448			end loop;
449			Clock		<= '0';
450		end procedure;
