494			constant InitialValue	: in	boolean					:= FALSE
495		) is
496			constant PROCESS_ID	: T_SIM_PROCESS_ID			:= simRegisterProcess(TestID, "simGenerateWaveform");
497			variable State			: boolean;
498		begin
