519		procedure simGenerateWaveform(
520			constant TestID				: in	T_SIM_TEST_ID;
521			signal	 Wave					: out	std_logic;
522			constant Waveform			: in	T_SIM_WAVEFORM;
523			constant InitialValue	: in	std_logic				:= '0'
524		) is
525			constant PROCESS_ID	: T_SIM_PROCESS_ID			:= simRegisterProcess(TestID, "simGenerateWaveform");
526			variable State : std_logic;
527		begin
528			State	:= InitialValue;
529			Wave	<= State;
530			for i in Waveform'range loop
531				wait for Waveform(i);
532				State		:= not State;
533				Wave		<= State;
534				exit when simIsStopped(TestID);
535			end loop;
536			simDeactivateProcess(PROCESS_ID);
537		end procedure;
