968		begin
969			-- WORKAROUND: for Mentor QuestaSim/ModelSim
970			--	Version:	10.4c
971			--	Issue:
972			--		return (0 => Pause, 1 => ResetPulse); always evaluates to (0 ns, 10 ns),
973			--		regardless of the passed function parameters
974			--	Bugfix:
975			--		The bugfix will be included in 10.5a, but this workaround must be
976			--		present until Altera updates the embedded ModelSim Altera Edition.
977			p  := Pause;
978			rp := ResetPulse;
979			return (0 => p, 1 => rp);
